await page.setViewportSize({ width: 1440, height: 800 });
await page.goto('http://127.0.0.1:5173/demos/dyamic-layouts-sidebars/list-detail');
await page.waitForTimeout(700);
return await page.evaluate(() => {
  const main = document.querySelector('[data-slot="sidebar-inset"]');
  const aside = document.querySelector('aside');
  const cs = getComputedStyle(main);
  const acs = getComputedStyle(aside);
  window.scrollTo(0, 0);
  const a = aside.getBoundingClientRect();
  const m = main.getBoundingClientRect();
  return {
    variant: document.querySelector('[data-slot="sidebar"]')?.getAttribute('data-variant'),
    viewport: window.innerHeight,
    mainMargin: { top: cs.marginTop, bottom: cs.marginBottom },
    asideCss: { position: acs.position, top: acs.top, height: acs.height },
    mainBottom: +m.bottom.toFixed(1),
    asideRect: { top: +a.top.toFixed(1), bottom: +a.bottom.toFixed(1) },
    asideBottomVsPanelBottom: +(a.bottom - (window.innerHeight - parseFloat(cs.marginBottom))).toFixed(1),
    asideBottomVsViewport: +(a.bottom - window.innerHeight).toFixed(1),
  };
});
